import{_ as a,o as e,c as s,a2 as d}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"命令与权限","description":"","frontmatter":{},"headers":[],"relativePath":"gtpay/commands.md","filePath":"gtpay/commands.md","lastUpdated":1784433066000}'),i={name:"gtpay/commands.md"};function p(o,t,n,l,c,h){return e(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="命令与权限" tabindex="-1">命令与权限 <a class="header-anchor" href="#命令与权限" aria-label="Permalink to &quot;命令与权限&quot;">​</a></h1><p>主命令：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay</span></span></code></pre></div><p>别名：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pay</span></span></code></pre></div><h2 id="玩家命令" tabindex="-1">玩家命令 <a class="header-anchor" href="#玩家命令" aria-label="Permalink to &quot;玩家命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/gtpay buy &lt;金额&gt; [渠道]</code></td><td>创建点券充值订单</td></tr><tr><td><code>/gtpay gift &lt;礼包ID&gt; [渠道]</code></td><td>购买固定价格礼包</td></tr><tr><td><code>/gtpay gui [GUI文件]</code></td><td>打开充值 GUI，默认打开 <code>main.yml</code></td></tr><tr><td><code>/gtpay gifts [GUI文件]</code></td><td>打开礼包 GUI，默认打开 <code>gifts.yml</code></td></tr><tr><td><code>/gtpay sponsor [方案ID]</code></td><td>查看累计赞助金额和排名</td></tr><tr><td><code>/gtpay sponsor claim &lt;方案ID&gt; &lt;金额&gt;</code></td><td>领取指定档位奖励</td></tr><tr><td><code>/gtpay orders</code></td><td>查看自己的近期订单</td></tr><tr><td><code>/gtpay status &lt;订单号&gt;</code></td><td>查询订单状态</td></tr><tr><td><code>/gtpay show [订单号]</code></td><td>重新显示仍在等待支付的二维码</td></tr><tr><td><code>/gtpay close</code></td><td>取消当前待支付订单</td></tr><tr><td><code>/gtpay help</code></td><td>查看帮助</td></tr></tbody></table><h2 id="点券充值" tabindex="-1">点券充值 <a class="header-anchor" href="#点券充值" aria-label="Permalink to &quot;点券充值&quot;">​</a></h2><p>微信充值 10 元：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay buy 10 wechat</span></span></code></pre></div><p>支付宝充值 50 元：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay buy 50 alipay</span></span></code></pre></div><p>省略渠道时使用 <code>config.yml</code> 中 <code>payment.channels</code> 的第一个渠道：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay buy 10</span></span></code></pre></div><h2 id="礼包购买" tabindex="-1">礼包购买 <a class="header-anchor" href="#礼包购买" aria-label="Permalink to &quot;礼包购买&quot;">​</a></h2><p>购买 <code>vip_30</code> 礼包：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay gift vip_30 wechat</span></span></code></pre></div><p>礼包价格来自 <code>gifts.yml</code>，玩家不能在命令中修改礼包金额。</p><h2 id="取消订单" tabindex="-1">取消订单 <a class="header-anchor" href="#取消订单" aria-label="Permalink to &quot;取消订单&quot;">​</a></h2><p>付款地图显示期间按 <code>Q</code>：</p><ul><li>不会丢出玩家真实物品。</li><li>当前待支付订单会被取消。</li><li>该订单占用的分币金额会释放。</li><li>已取消订单不能继续付款。</li></ul><p>也可以执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay close</span></span></code></pre></div><p>该命令不是单纯隐藏地图，同样会取消当前订单。</p><h2 id="累计赞助" tabindex="-1">累计赞助 <a class="header-anchor" href="#累计赞助" aria-label="Permalink to &quot;累计赞助&quot;">​</a></h2><p>查看永久累计赞助：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay sponsor lifetime</span></span></code></pre></div><p>领取永久累计 100 元档位：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay sponsor claim lifetime 100</span></span></code></pre></div><p>查看月累计赞助：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay sponsor monthly</span></span></code></pre></div><h2 id="管理命令" tabindex="-1">管理命令 <a class="header-anchor" href="#管理命令" aria-label="Permalink to &quot;管理命令&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>权限</th><th>说明</th></tr></thead><tbody><tr><td><code>/gtpay web open</code></td><td><code>gtpay.admin</code></td><td>打开本地管理页</td></tr><tr><td><code>/gtpay web close</code></td><td><code>gtpay.admin</code></td><td>关闭本地管理页</td></tr><tr><td><code>/gtpay web status</code></td><td><code>gtpay.admin</code></td><td>查看本地管理页状态</td></tr><tr><td><code>/gtpay reload</code></td><td><code>gtpay.admin</code></td><td>重载全部配置</td></tr><tr><td><code>/gtpay retry &lt;订单号&gt;</code></td><td><code>gtpay.admin</code></td><td>重试发放已支付但未完成的订单</td></tr></tbody></table><p>控制台可以直接执行管理命令。</p><h2 id="礼包权限" tabindex="-1">礼包权限 <a class="header-anchor" href="#礼包权限" aria-label="Permalink to &quot;礼包权限&quot;">​</a></h2><p>礼包可以单独配置购买权限：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">vip_30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gtpay.gift.vip30&quot;</span></span></code></pre></div><p>玩家需要：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay.gift.vip30</span></span></code></pre></div><p>权限留空时所有玩家都可以购买。</p><h2 id="gui-按钮权限" tabindex="-1">GUI 按钮权限 <a class="header-anchor" href="#gui-按钮权限" aria-label="Permalink to &quot;GUI 按钮权限&quot;">​</a></h2><p>GUI 图标也可以单独设置：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gtpay.menu.vip&quot;</span></span></code></pre></div><p>玩家没有权限时，该按钮不会显示。</p>`,44)])])}const u=a(i,[["render",p]]);export{g as __pageData,u as default};
